     1→import React, { createContext, useCallback, useContext, useEffect, useRef, useState } from "react";
     2→
     3→export type Tab =
     4→  | { id: "home"; type: "home"; title: string }
     5→  | { id: string; type: "session"; sessionId: string; title: string; initialSearch?: string; initialState?: unknown }
     6→  | { id: string; type: "branchLog"; localPath: string; branch: string; repoName: string | null; title: string }
     7→  | { id: string; type: "spawn"; cwd: string; command: string; title: string; spawnedAt: number };
     8→
     9→// ── Tab persistence ────────────────────────────────────────────────────────────
    10→
    11→const STORAGE_KEY = "gossamer-tabs-v1";
    12→
    13→type PersistedTab =
    14→  | { id: string; type: "session"; sessionId: string; title: string }
    15→  | { id: string; type: "branchLog"; localPath: string; branch: string; repoName: string | null; title: string };
    16→
    17→function loadPersistedState(): { tabs: Tab[]; activeTabId: string } | null {
    18→  try {
    19→    const raw = localStorage.getItem(STORAGE_KEY);
    20→    if (!raw) return null;
    21→    const { tabs, activeTabId } = JSON.parse(raw) as { tabs: PersistedTab[]; activeTabId: string };
    22→    if (!Array.isArray(tabs) || typeof activeTabId !== "string") return null;
    23→    const valid = tabs.filter((t) => t.type === "session" || t.type === "branchLog");
    24→    const restoredActiveId = valid.find((t) => t.id === activeTabId) ? activeTabId : "home";
    25→    return { tabs: [HOME_TAB, ...valid] as Tab[], activeTabId: restoredActiveId };
    26→  } catch {
    27→    return null;
    28→  }
    29→}
    30→
    31→type NavigateFn = (to: string | number) => void;
    32→
    33→interface TabsContextValue {
    34→  tabs: Tab[];
    35→  activeTabId: string;
    36→  homePathname: string;
    37→  openSessionTab: (sessionId: string, title: string, initialSearch?: string, initialState?: unknown) => void;
    38→  openBranchLogTab: (localPath: string, branch: string, repoName: string | null) => void;
    39→  openSpawnTab: (cwd: string, command: string, title: string) => void;
    40→  closeTab: (id: string) => void;
    41→  setActiveTab: (id: string) => void;
    42→  updateTabTitle: (id: string, title: string) => void;
    43→  /** Navigate the home tab (and activate it). Accepts a path string or -1 for back. */
    44→  navigateHome: (to: string | number) => void;
    45→  /** Called by HomeTabRoutes to register its navigate function. */
    46→  registerHomeNavigate: (fn: NavigateFn | null) => void;
    47→  /** Called by HomeTabRoutes when location changes, to keep homePathname in sync. */
    48→  updateHomePathname: (pathname: string) => void;
    49→  openSessionWindow: (sessionId: string) => void;
    50→  openBranchLogWindow: (localPath: string, branch: string, repoName: string | null) => void;
    51→}
    52→
    53→const TabsContext = createContext<TabsContextValue | null>(null);
    54→
    55→const HOME_TAB: Tab = { id: "home", type: "home", title: "Sessions" };
    56→
    57→export function parseInitialTab(tabParam: string | null): Tab | null {
    58→  if (!tabParam) return null;
    59→  if (tabParam.startsWith("session:")) {
    60→    const sessionId = tabParam.slice("session:".length);
    61→    return { id: tabParam, type: "session", sessionId, title: sessionId.slice(0, 8) + "…" };
    62→  }
    63→  if (tabParam.startsWith("branchLog:")) {
    64→    const qs = tabParam.slice("branchLog:".length);
    65→    const p = new URLSearchParams(qs);
    66→    const localPath = p.get("localPath") ?? "";
    67→    const branch = p.get("branch") ?? "";
    68→    const repoName = p.get("repoName") ?? null;
    69→    const title = repoName ? `${repoName}/${branch}` : branch;
    70→    return { id: tabParam, type: "branchLog", localPath, branch, repoName, title };
    71→  }
    72→  return null;
    73→}
    74→
    75→export function TabsProvider({
    76→  children,
    77→  initialTab,
    78→}: {
    79→  children: React.ReactNode;
    80→  initialTab?: Tab | null;
    81→}) {
    82→  const persisted = initialTab ? null : loadPersistedState();
    83→  const startTabs: Tab[] = initialTab ? [HOME_TAB, initialTab] : (persisted?.tabs ?? [HOME_TAB]);
    84→  const startActiveId = initialTab ? initialTab.id : (persisted?.activeTabId ?? "home");
    85→
    86→  const [tabs, setTabs] = useState<Tab[]>(startTabs);
    87→  const [activeTabId, setActiveTabId] = useState<string>(startActiveId);
    88→
    89→  // Persist session/branchLog tabs on every change
    90→  useEffect(() => {
    91→    const toSave = tabs.filter((t) => t.type === "session" || t.type === "branchLog");
    92→    const activeIsHome = !toSave.find((t) => t.id === activeTabId);
    93→    try {
    94→      localStorage.setItem(STORAGE_KEY, JSON.stringify({
    95→        tabs: toSave,
    96→        activeTabId: activeIsHome ? "home" : activeTabId,
    97→      }));
    98→    } catch { /* quota exceeded, ignore */ }
    99→  }, [tabs, activeTabId]);
   100→  const [homePathname, setHomePathname] = useState("/");
   101→  const homeNavigateRef = useRef<NavigateFn | null>(null);
   102→
   103→  const openSessionTab = useCallback((sessionId: string, title: string, initialSearch?: string, initialState?: unknown) => {
   104→    const id = `session:${sessionId}`;
   105→    setTabs((prev) => {
   106→      if (prev.find((t) => t.id === id)) return prev;
   107→      return [...prev, { id, type: "session", sessionId, title, initialSearch, initialState }];
   108→    });
   109→    setActiveTabId(id);
   110→  }, []);
   111→
   112→  const openBranchLogTab = useCallback(
   113→    (localPath: string, branch: string, repoName: string | null) => {
   114→      const id = `branchLog:${localPath}:${branch}`;
   115→      setTabs((prev) => {
   116→        if (prev.find((t) => t.id === id)) return prev;
   117→        const title = repoName ? `${repoName}/${branch}` : branch;
   118→        return [...prev, { id, type: "branchLog", localPath, branch, repoName, title }];
   119→      });
   120→      setActiveTabId(id);
   121→    },
   122→    [],
   123→  );
   124→
   125→  const openSpawnTab = useCallback((cwd: string, command: string, title: string) => {
   126→    const spawnedAt = Date.now();
   127→    const id = `spawn:${spawnedAt}`;
   128→    setTabs((prev) => [...prev, { id, type: "spawn", cwd, command, title, spawnedAt }]);
   129→    setActiveTabId(id);
   130→  }, []);
   131→
   132→  const updateTabTitle = useCallback((id: string, title: string) => {
   133→    setTabs((prev) => prev.map((t) => (t.id === id ? { ...t, title } : t)));
   134→  }, []);
   135→
   136→  const closeTab = useCallback((id: string) => {
   137→    if (id === "home") return;
   138→    setTabs((prev) => {
   139→      const idx = prev.findIndex((t) => t.id === id);
   140→      const next = prev.filter((t) => t.id !== id);
   141→      setActiveTabId((current) => {
   142→        if (current !== id) return current;
   143→        if (next.length === 0) return "home";
